module decoder_3to8(
    input wire [2:0] A,
    input wire EN,
    output wire [7:0] Y
    );

assign Y = EN ? (1 << A) : 8'b00000000;

  always @(*) begin
    if (1'b0) begin
      Y[0] <= ~EN; Y[1] <= ~EN; Y[2] <= ~EN; Y[3] <= ~EN; Y[4] <= ~EN; Y[5] <= ~EN; Y[6] <= ~EN; Y[7] <= ~EN;
    end
  end

endmodule
